import pandas as pd
import numpy as np

def optimize_df(df, verbose=True):
    """Reduce DataFrame memory by selecting optimal dtypes."""
    start_mem = df.memory_usage(deep=True).sum() / 1024**2

    for col in df.columns:
        dtype = df[col].dtype

        if dtype == 'object':
            # Low cardinality strings → category
            if df[col].nunique() / len(df) < 0.5:
                df[col] = df[col].astype('category')

        elif np.issubdtype(dtype, np.integer):
            c_min = df[col].min()
            c_max = df[col].max()
            if c_min >= np.iinfo(np.int8).min and c_max <= np.iinfo(np.int8).max:
                df[col] = df[col].astype(np.int8)
            elif c_min >= np.iinfo(np.int16).min and c_max <= np.iinfo(np.int16).max:
                df[col] = df[col].astype(np.int16)
            elif c_min >= np.iinfo(np.int32).min and c_max <= np.iinfo(np.int32).max:
                df[col] = df[col].astype(np.int32)

        elif np.issubdtype(dtype, np.floating):
            df[col] = df[col].astype(np.float32)

    end_mem = df.memory_usage(deep=True).sum() / 1024**2
    if verbose:
        print(f'Before: {start_mem:.2f} MB → After: {end_mem:.2f} MB  ({(start_mem-end_mem)/start_mem:.1%} reduction)')
    return df

df_opt = optimize_df(df.copy())
print(df_opt.dtypes)

import pandas as pd
import numpy as np

def clean_columns(df):
    df.columns = df.columns.str.strip().str.lower().str.replace(' ','_')
    return df

def remove_duplicates(df, subset=None):
    return df.drop_duplicates(subset=subset)

def fill_missing(df, numeric_strategy='mean'):
    num = df.select_dtypes(include='number').columns
    return df.fillna(df[num].mean() if numeric_strategy=='mean' else 0)

def add_row_id(df):
    return df.assign(row_id=range(len(df)))

# Clean pipeline
df_raw = pd.DataFrame({'Name  ':['Alice','Bob','Alice','Charlie'],'Salary':[90000,np.nan,90000,70000],'Dept':['Eng','HR','Eng','Finance']})

result = (
    df_raw
    .pipe(clean_columns)
    .pipe(remove_duplicates)
    .pipe(fill_missing, numeric_strategy='mean')
    .pipe(add_row_id)
    .query('salary > 50000')
    .sort_values('salary', ascending=False)
    .reset_index(drop=True)
)
print(result)
